function ModelCallHero:OnModelInit()
	self._timerList = {}
	self._getServerTime = ModelCallHero.USE_SERVERTIME == 1
	self:InitCallRef()
	self:ModelNetMsgRecv(LProtoIds.MagicResp,function(...)
		-- 魔镜返回
		self:OnMagicResp(...)
	end)
	self:ModelNetMsgRecv(LProtoIds.HeartResp,function(...)
		-- 心灵返回
		self:OnHeartResp(...)
	end)
	self:ModelNetMsgRecv(LProtoIds.CallHeroResp,function(...)
		-- 获得返回
		self:OnCallHeroResp(...)
	end)
	self:ModelNetMsgRecv(LProtoIds.CallLogResp,function(...)
		-- 日志
		self:OnCallLogResp(...)
	end)

	self:ModelNetMsgRecv(LProtoIds.MagicWheelInfoResp,function(...)
		self:OnMagicWheelInfoResp(...)
	end)

	self:ModelNetMsgRecv(LProtoIds.MagicWheelResp,function(...)
		self:OnMagicWheelResp(...)
	end)
end

--在协议数据处理完之后需要调用finish
function ModelCallHero:OnModelRequest()
	if not self._heartCallHeroRefId then
		self:InitHeartCallRefId()
	end
	self._isMagicEff = true
	self._timerList = {}
	self:ModelFinish()
	self:CallOpt(1)
end

