function ModelCallHero:InitCallRef()
	self._callRefData = {}
	local callRefData = self._callRefData
	for k,v in pairs(GameTable.SummonRef) do
		local extractType = v.extractType
		local temp = callRefData[extractType]
		if not temp then
			temp = {}
			callRefData[extractType] = temp
		end
		temp[k] = v
	end
	local sortFunc = function(tab1,tab2)
		return tab1.srot < tab2.srot
	end
	for i,v in ipairs(callRefData) do
		table.sort(v,sortFunc)
	end
end

function ModelCallHero:OnMagicReq(extractType)
	local pb = LProtoHelper.CreateProto(LProtoIds.MagicReq)
	pb.extractType = extractType
	SendMessage(pb,LProtoIds.MagicReq)
end

function ModelCallHero:OnMagicResp(pb,ret)
	self:ClearAllTime()
	local callHero = {}
	self._callHeroData = callHero
	local datas = pb.callHeroInfo
	for i, v in ipairs(datas) do
		local refId = v.refId
		local data = {
			refId = refId,
			freeNum = v.freeNum,
			callNum = v.callNum,
			refreshTimeOfFreeNum = v.refreshTimeOfFreeNum,
			refreshTimeOfCallNum = v.refreshTimeOfCallNum,
			allNum = v.allNum,
			nextRefreshTimeOfFreeNum = v.nextRefreshTimeOfFreeNum,
			nextRefreshTimeOfCallNum = v.nextRefreshTimeOfCallNum,
			guaranteesNum = v.guaranteesNum,
			callNum2 = v.callNum2
		}
		callHero[refId] = data
	end

	if self._getServerTime then
		self:StartMirrorServerTimers()
	else
		self:StartMirrorTimers()
	end

	self._isWaitCallRet = false
end

function ModelCallHero:IsMagicCalled()
	if not self._callHeroData then
		return false
	end
    local data = self._callHeroData[ModelCallHero.CALL_TYPE_SPECIAL]
    if not data then
        return false
    end

    return data.allNum > 0
end

function ModelCallHero:IsWaitCallRet()
    return self._isWaitCallRet or false
end


function ModelCallHero:StartMirrorServerTimers()
	local refData = self:GetTypeData(1)
	if not refData then return end
	local callHeroData = self._callHeroData
	for k,v in pairs(refData) do
		local freeExtractNum = v.freeExtractNum
		if freeExtractNum ~= 0 then
			local serverData = callHeroData[k]
			if serverData and serverData.freeNum == 0 then
				self:CreateServerTimer(serverData.nextRefreshTimeOfFreeNum,k)
			end
		end
	end
end

function ModelCallHero:CreateServerTimer(endTime,refId)
	self:ClearTimer(nil,refId)
	if not self._timerList then self._timerList = {} end
	endTime = endTime/1000
	self._timerList[refId] = LxTimer.LoopTimeCall(function()
		self:CallHeroCountDown(endTime)
	end, 1, false, -1)
end

function ModelCallHero:CallHeroCountDown(times)
	local curTime = GetTimestamp()
	local lastTime = times - curTime
	if lastTime <= 0 then
		self:ClearAllTime(true)
	end
end

-- 免费召唤时间为服务端推送
function ModelCallHero:StartMirrorTimers()
	local refData = self:GetTypeData(1)
	local callHeroData = self._callHeroData
	for k,v in pairs(refData) do
		local freeExtractNum = v.freeExtractNum
		if freeExtractNum ~= 0 then
			local serverData = callHeroData[k]
			if serverData then
				local freeNum = serverData.freeNum
				if freeNum == 0 then
					local freeExtractTime = v.freeExtractTime
					local index = v.type
					self:CreateTimer(freeExtractTime,index,k)
				end
			end
		end
	end
end

function ModelCallHero:CreateTimer(freeExtractTime,index,refId)
	self:ClearTimer(nil,index)
	if not self._timerList then
		self._timerList = {}
	end
	freeExtractTime = string.split(freeExtractTime,"=")
	if tonumber(freeExtractTime[1]) == 1 then
		self._timerList[index] = LxTimer.LoopTimeCall(function()
			self:SetDayTimer(tonumber(freeExtractTime[2]),index,refId)
		end, 1, false, -1)
	else
		self._timerList[index] = LxTimer.LoopTimeCall(function()
			self:SetHourTimer(tonumber(freeExtractTime[2]),index,refId)
		end, 1, false, -1)
	end
end

function ModelCallHero:SetDayTimer(addHour,index,refId)
	local curTime = GetTimestamp()
	local curYear = tonumber(LUtil.OSDate("%Y",curTime))
	local curMon = tonumber(LUtil.OSDate("%m",curTime))
	local curDay = tonumber(LUtil.OSDate("%d",curTime))
	local curHour = tonumber(LUtil.OSDate("%H",curTime))
	local addDay = 0
	if curHour >= addHour then addDay = 1 end
	local newDay = curDay + addDay
	local serverData = self._callHeroData[refId]
	if serverData then
		local refreshTimeOfFreeNum = serverData.refreshTimeOfFreeNum
		local serDay = tonumber(LUtil.OSDate("%d",refreshTimeOfFreeNum/1000))
		if newDay - serDay > 1 then
			self:ClearAllTime(true)
			return
		end
	end
	local nextDayTime = LUtil.OSTime({hour = addHour,day = newDay,month = curMon,year = curYear})
	local remainTime = nextDayTime - curTime
	if remainTime <= 0 then
		self:ClearTimer(true,index)
	end
end

function ModelCallHero:SetHourTimer(addHour,index,refId)
	local serverData = self._callHeroData[refId]
	local serverTime = serverData.refreshTimeOfFreeNum / 1000
	local curYear = tonumber(LUtil.OSDate("%Y",serverTime))
	local curMon = tonumber(LUtil.OSDate("%m",serverTime))
	local curDay = tonumber(LUtil.OSDate("%d",serverTime))
	local curHour = tonumber(LUtil.OSDate("%H",serverTime))
	local nextDayTime = LUtil.OSTime({hour = curHour + addHour,day = curDay,month = curMon,year = curYear})
	local curTime = tonumber(GetTimestamp())
	if nextDayTime < curTime then
		self:ClearTimer(true,index)
	else
		local remainTime = nextDayTime - curTime
		if remainTime <= 0 then
			self:ClearTimer(true,index)
		end
	end
end

function ModelCallHero:ClearTimer(request,index)
	local timerList = self._timerList
	if timerList then
		local timer = timerList[index]
		if timer then
			LxTimer.DelayTimeStop(timer)
			timerList[index] = nil
		end
	end
	if request then
		self:CallOpt(1)
	end
end

function ModelCallHero:ClearAllTime(request)
	if request then self:CallOpt(1) end
	if table.isempty(self._timerList) then return end
	for k,v in pairs(self._timerList) do
		LxTimer.DelayTimeStop(v)
	end
	self._timerList = {}
end

function ModelCallHero:GetCallHeroData()
	return self._callHeroData or {}
end

function ModelCallHero:OnHeartReq(extractType)
	local pb = LProtoHelper.CreateProto(LProtoIds.HeartReq)
	pb.extractType = extractType
	SendMessage(pb,LProtoIds.HeartReq)
end

function ModelCallHero:OnHeartResp(pb,ret)
	local heartData = {}
	self._heartData = heartData
	local datas = pb.callHeroInfo
	for i, v in ipairs(datas) do
		local refId = v.refId
		local data = {
			refId = refId,
			freeNum = v.freeNum,
			callNum = v.callNum,
			diamondNum = v.callNum2 or 0, --钻石召唤次数
			refreshTimeOfFreeNum = v.refreshTimeOfFreeNum,
			refreshTimeOfCallNum = v.refreshTimeOfCallNum,
		}
		heartData[refId] = data
	end
end

function ModelCallHero:GetHeartData()
	return self._heartData or {}
end

function ModelCallHero:OnMagicWheelInfoReq(type)
	local pb = LProtoHelper.CreateProto(LProtoIds.MagicWheelInfoReq)
	pb.type = type
	SendMessage(pb,LProtoIds.MagicWheelInfoReq)
end

function ModelCallHero:CallOpt(page,subPage)
	if page == 1 then
		self:OnMagicReq(1)
	elseif page == 2 then
		self:OnHeartReq(2)
	elseif page == 3 then  -- 辛运魔轮请求
		local type = tonumber(subPage)
		type = type == 2 and ModelCallHero.MIRACLE or ModelCallHero.LUCKY
		self:OnMagicWheelInfoReq(type)
	end
end

function ModelCallHero:OnCallHeroReq(refId,num, consumeRefId)
	FireEvent(EventNames.ON_MOJING_ZHAOHUAN)
	local pb = LProtoHelper.CreateProto(LProtoIds.CallHeroReq)
	pb.refId = refId
	pb.num = num
	pb.consumeRefId = consumeRefId or 0
	SendMessage(pb,LProtoIds.CallHeroReq)
	if refId == ModelCallHero.CALL_TYPE_SPECIAL then
		self._isWaitCallRet = true
	end

	self:SetCallReqProtect(true)

end

-- 魔轮重置请求
function ModelCallHero:OnMagicWheelResetReq(type)
	local pb = LProtoHelper.CreateProto(LProtoIds.MagicWheelResetReq)
	pb.type = type
	SendMessage(pb,LProtoIds.MagicWheelResetReq)
end

-- 魔轮抽取请求:wheelType魔轮抽取类型：1单次抽取 2批量抽取
function ModelCallHero:OnMagicWheelReq(type,wheelType)
	local pb = LProtoHelper.CreateProto(LProtoIds.MagicWheelReq)
	pb.type = type
	pb.wheelType = wheelType
	SendMessage(pb,LProtoIds.MagicWheelReq)
end

-- 魔轮幸运奖励领取请求
function ModelCallHero:OnMagicLuckyReceiveReq(luckyIdList)
	local pb = LProtoHelper.CreateProto(LProtoIds.MagicLuckyReceiveReq)
	for i,luckyId in ipairs(luckyIdList) do
		pb.luckyId:append(luckyId)
	end
	SendMessage(pb,LProtoIds.MagicLuckyReceiveReq)
end
