function ModelCallHero:OnCallHeroResp(pb,ret)

	if ret == -1 then return end
	local itemList = {}
	local callRefId = pb.refId

	local ref = self:GetCallRefByRefId(callRefId)
	local fixedCfg,extractType

	if ref then
		fixedCfg = LxDataHelper.ParseItem_3(ref.fixedReward)
		extractType = ref.extractType -- self:GetExtractType(callRefId)
	end

	local rewards = pb.rewards
	local callNum = pb.num
	local rankValue = pb.rankValue
	local callLogId = pb.callLogId
	local rank = pb.rank
	local haveUpStar = false

	local getHeroList = {}

	local fixedReward = nil
	for i = 1,#rewards do
		local data = rewards[i]
		local rewardType = data.type
		local itemId = tonumber(data.itemId)
		local count = tonumber(data.count)
		local tab = {
			itype = rewardType,
			itemId = itemId,
			count = count
		}
		if (not haveUpStar) and rewardType == 2 then
			local initStar = gModelHero:GetHeroInitStarByRefId(itemId)
			if initStar then haveUpStar = initStar >= 4 end
		end
		if extractType == 1 then
			if rewardType == 2 then
				table.insert(itemList, tab)

				table.insert(getHeroList,{
					itype = rewardType,
					itemId = itemId,
					count = count
				})
			end
		else
			if rewardType == 2 then
				for _i = 1,count do
					local t = table.clone(tab)
					table.insert(itemList, t)

					table.insert(getHeroList,{
						itype = rewardType,
						itemId = itemId,
						count = count
					})
				end
			else
				table.insert(itemList, tab)
			end
		end

		if fixedCfg and itemId == fixedCfg.itemId then
			fixedReward =
			{
				itemId = itemId,
				itemType = rewardType,
				itemNum = count,
			}
		end

	end

	FireEvent(EventNames.ON_CALL_HERO_REWARD, callNum, callRefId, itemList, fixedReward )

	if callRefId == ModelCallHero.CALL_TYPE_SPECIAL then
		self:CallOpt(1) --特殊召唤需要立即刷新召唤数据 情景副本要用
	elseif callRefId == ModelCallHero.CALL_TYPE_REGRESSION then
		self:OnMagicReq(4)
	end
	

	local len,sacrificeList = self:GetHeroSacrificeNumAndList()
	if len == 0 then
		self:SetCallReqProtect(false)
	end

	--【Y英雄召唤】删除旧版的召唤界面
	-- if self:CheckIsShowNew() then
		local func = function()
			local wndIns = GF.FindFirstWndByName("UIMirrorYellSagaSow")
			local isOpenWnd = wndIns ~= nil
			local para =
			{
				itemList = itemList,
				refId = callRefId,
				haveUpStar = haveUpStar,
				callNum = callNum,
				rankValue = rankValue,
				callLogId = callLogId,
				rank = rank,
				fixedReward = fixedReward,
				isOpenWnd = isOpenWnd,
			}
			GF.OpenWndTop("UIYellSagaAwardNew",para)
		end

		if extractType == 1 or extractType == 4 then
			--[[		local wndIns = GF.FindFirstWndByName("UIMirrorYellSagaSow")
                    if wndIns then
                        FireEvent(EventNames.ON_MOJING_RET,func,getHeroList)
                    else
                        func()
                    end]]
			if ModelCallHero.MIRRORCALLHERO_STATUS == 1 then
				if (gModelCallHero:GetMirrorCallJumpAniStats() and extractType==1) or 
				(gModelRegression:GetRegressionCallJumpAniStats() and extractType==4) then
					func()
				elseif PRODUCT_G_VER ~= 0 then
					func()
				else
					local wndIns = GF.FindFirstWndByName("UIYellSagaAwardNew")
					if wndIns then
						func()
					else
						if self:CheckIsExamineSex() then
							func()
						else
							GF.OpenWnd("UIMirrorYellSagaSow",{
								viewType = 1,
								callRefId = callRefId,
								extractType = extractType,
								mirrorCallEndFunc = func,
								getHeroList = getHeroList,
								callNum = callNum,
							})

						end
					end
					--func()
				end
			else
				local wndIns = GF.FindFirstWndByName("UIMirrorYellSagaSow")
				if wndIns then
					FireEvent(EventNames.ON_MOJING_RET,func,getHeroList)
				else
					func()
				end
			end
		elseif extractType == 2 then
			local wndIns = GF.FindFirstWndByName("UIYellSagaAwardNew")
			if wndIns then
				func()
			else
				GF.OpenWnd("UIMirrorYellSagaSow",{
					viewType = 2,
					callRefId = callRefId,
					extractType = extractType,
					showRewardFunc = func,
