function ModelCallHero:OnMagicWheelInfoResp(pb)
	if not self._wheelInfoMap then
		self._wheelInfoMap= {}
	end

	self._wheelInfoMap[pb.type] = {
		extractCountToday = pb.extractCountToday
	}
end

function ModelCallHero:OnMagicWheelResp(pb)
	local callNum =self:GetWheelCallNum(pb.type,pb.wheelType)
	if not self._wheelInfoMap then
		self._wheelInfoMap= {}
	end
	local data = self._wheelInfoMap[pb.type]

	local cnt = data and data.extractCountToday or  0
	cnt = cnt + callNum
	self._wheelInfoMap[pb.type] =
	{
		extractCountToday = cnt
	}
	FireEvent(EventNames.ON_CALL_MAGICWHEEL_REWARD, callNum, pb.itemDetail)
end


function ModelCallHero:OnCallLogReq(callType,sid)
	local pb = LProtoHelper.CreateProto(LProtoIds.CallLogReq)
	pb.type = callType
	if sid then
		pb.sid = sid
	end
	SendMessage(pb,LProtoIds.CallLogReq)
end

function ModelCallHero:OnCallLogResp(pb,ret)
	self. _logList = {}
	local logList = self._logList
	local logs = pb.logs
	for i,v in ipairs(logs) do
		local fixedRewardList,extraRewardList,consumeList = {},{},{}
		local fixedReward,extraReward,consume = v.fixedReward,v.extraReward,v.consume
		local otherInfo = v.otherInfo
		for _i,_v in ipairs(fixedReward) do
			local data = {
				itemId = _v.itemId,
				count = _v.count,
				type = _v.type,
			}
			table.insert(fixedRewardList,data)
		end
		for _i,_v in ipairs(extraReward) do
			local data = {
				itemId = _v.itemId,
				count = _v.count,
				type = _v.type,
			}
			table.insert(extraRewardList,data)
		end
		for _i,_v in ipairs(consume) do
			local data = {
				itemId = _v.itemId,
				count = _v.count,
				type = _v.type,
			}
			table.insert(consumeList,data)
		end
		local data = {
			refId = v.refId,
			num = v.num,
			fixedReward = fixedRewardList,
			extraReward = extraRewardList,
			consume = consumeList,
			createTime = v.createTime,
			rankValue = v.rankValue,
			id = v.id,
			otherInfo = otherInfo
		}
		table.insert(logList,data)
	end
end

