function ModelCallHero:GetInitMagicWheelRewardRefByRefId(refId)
	local initMagicWheelRewardRefList = self._initMagicWheelRewardRefList
	if not initMagicWheelRewardRefList then
		initMagicWheelRewardRefList = {}
		self._initMagicWheelRewardRefList = initMagicWheelRewardRefList
	end
	local data = initMagicWheelRewardRefList[refId]
	if not data then
		local ref = self:GetMagicWheelRewardRefByRefId(refId)
		if ref then
			data = {}

			data.refId = refId
			data.type = ref.type
			data.reward = LxDataHelper.ParseItem_3(ref.reward)
			data.list = ref.list
			data.unlock = ref.unlock
			data.close = ref.close
			data.refreshRate = ref.refreshRate
			data.refreshMin = ref.refreshMin
			data.refreshMax = ref.refreshMax
			data.extractRate = ref.extractRate
			data.extractMin = ref.extractMin
			data.extractMax = ref.extractMax
			data.extractLimit = ref.extractLimit


			initMagicWheelRewardRefList[refId] = data
		end
	end
	return data
end

