function ModelCallHero:GetHeroSacrificeNumAndList()
	local len = 0
	local autoSacrifice = gModelHero:GetAutoSacrificeStatus()
	if not autoSacrifice then return len end
	local sacrificeList = {}
	local heroList = gModelHero:GetHeroList()
	local star,refId
	for k,v in pairs(heroList) do
		refId = v:GetRefId()
		if not gModelSpiritHero:CheckIsSpiritHero(refId) then
			star = v:GetStar()
			if star <= ModelCallHero.SACRIFICE_SEL_STAR then
				local status = v:GetStatus()
				if status == 0 then
					local id = v:GetId()
					sacrificeList[id] = id
					len = len + 1
				end
			end
		end
	end
	return len,sacrificeList
end

function ModelCallHero:AutoSacrificeFunc()
	local len,sacrificeList = self:GetHeroSacrificeNumAndList()
	if len > 0 then
		gModelHero:OnHeroSacrificeReq(sacrificeList,1)
	end
end

function ModelCallHero:CheckCallIsEnough(refId,type,srcWnd)
	local callTimes = type == 1 and 1 or 10
	if gModelGeneral:IsFullHeroBag(callTimes,nil,nil,nil,nil,srcWnd) then
		return 1
	end

	if not self._callHeroData then
		return false
	end

	local serverData = self._callHeroData[refId]
	if not serverData then
		return false
	end

	if type == 1 then  --免费单抽
		if serverData.freeNum > 0 then
			return true
		end
	end

	local refData = self:GetCallRefByRefId(refId)

	local dayExtractNumMax = refData.dayExtractNumMax
	if serverData.callNum + callTimes > dayExtractNumMax then
		return false
	end

	local expend = nil
	if type == 1 then
		callTimes = 1
		expend = refData.oneExpend
	elseif type == 2 then
		callTimes = 10
		expend = refData.tenExpend
	end

	local costItem = nil
	local isEnough = false
	local expendItems = LxDataHelper.ParseItem_3List(expend,'|')
	if #expendItems == 1 then
		costItem = expendItems[1]
	elseif #expendItems == 2 then
		local firstItem = expendItems[1]
		if gModelGeneral:CheckItemListEnoughStatus({firstItem}) then
			isEnough = true
			costItem = firstItem
		else
			costItem = expendItems[2]
		end
	end

	if isEnough then
		return true
	end

	return gModelGeneral:CheckItemListEnoughStatus({costItem})
end

function ModelCallHero:CheckIsShieldHero(callRefId, refId)
	if not self._shieldHeroList then
		self._shieldHeroList = {}
	end

	local shieldHeroList = self._shieldHeroList[callRefId]
	if not shieldHeroList then
		self._shieldHeroList[callRefId] = {}

		local ref = self:GetCallRefByRefId(callRefId)
		local shieldHero = ref.shieldHero or ""
		local shieldHeroIdList = string.split(shieldHero, ',')
		for k,v in ipairs(shieldHeroIdList) do
			if not string.isempty(v) then
				local heroId = tonumber(v)
				self._shieldHeroList[callRefId][heroId] = true
			end
		end
	end

	return self._shieldHeroList[callRefId][refId]
end

---召唤请求
function ModelCallHero:SendCallHeroReq(refId,type,wndName,isTop,sendFunc)

	if self:IsCallProtected() then
		return
	end

	local callTimes = type == 1 and 1 or 10
	if gModelGeneral:IsFullHeroBag(callTimes,nil,nil,nil,nil,wndName) then
		return
	end

	if not self._callHeroData then
		return
	end
	local serverData = self._callHeroData[refId]
	if not serverData then
		return
	end

	local refData = self:GetCallRefByRefId(refId)

	if type == 1 then  --免费单抽
		if serverData.freeNum>0 then
			if sendFunc then sendFunc() end
			self:OnCallHeroReq(refId, callTimes, 0)
			return
		end
	end

	local expend = nil
	if type == 1 then
		callTimes = 1
		expend = refData.oneExpend
	elseif type == 2 then
		callTimes = 10
		expend = refData.tenExpend
	end

	local dayExtractNumMax = refData.dayExtractNumMax
	if serverData.callNum + callTimes > dayExtractNumMax then
		GF.ShowMessage(ccClientText(11626))
		return
	end
	local costItem = nil
	local isEnough = false
	local expendItems = LxDataHelper.ParseItem_3List(expend,'|')
	if #expendItems == 1 then
		costItem = expendItems[1]
	elseif #expendItems == 2 then
		local firstItem= expendItems[1]
		if gModelGeneral:CheckItemEnough(firstItem.itemId,firstItem.itemNum) then
			isEnough = true
			costItem = firstItem
		else
			costItem = expendItems[2]
		end
	end

	if not costItem then
		return
	end
	if costItem.itemId == 102001 then
		local diamondNum = math.max(refData.dayDiamondNumMax-serverData.callNum2,0)
		if refData.dayDiamondNumMax > 0 and callTimes > diamondNum  then 
			GF.ShowMessage(ccClientText(11680))
			return
		end
	end

	---检查物品数量
	if not isEnough then
		if not gModelGeneral:CheckItemEnough(costItem.itemId,costItem.itemNum) then
			local layer = LGameUI.UI_SORTLAYER_UIWND
			if isTop then
				layer = LGameUI.UI_SORTLAYER_UITOP
			end
			gModelGeneral:OpenGetWayWnd({itemId=costItem.itemId,srcWnd = wndName},layer)
			return
		 end
	end

	local callFunc = function()
		if sendFunc then sendFunc() end
		self:OnCallHeroReq(refId, callTimes, costItem.itemId)
	end

	local needTip = true
	local wndId = nil
	if costItem.itemId == 102001 then
		wndId = 50101
	else
		if refData.type == ModelCallHero.TYPE_1 then
			wndId = 50103
		elseif refData.type == ModelCallHero.TYPE_2 then
			wndId = 50104
		else
			needTip = false
		end
	end

	if gModelGuide:IsInGuide() and wndName == "UIMirNew" then
		needTip = false
	end

	if needTip then
		local fixedReward = LxDataHelper.ParseItem_3(refData.fixedReward)
		local rewardStr = ""
		if fixedReward then
			rewardStr =string.format("%s%s",fixedReward.itemNum * callTimes,gModelGeneral:GetCommonItemName(fixedReward))
		end
		local costStr = string.format("%s%s",costItem.itemNum,gModelGeneral:GetCommonItemName(costItem))
		local otherPara = {costStr,rewardStr,callTimes,ccLngText(refData.typeName)}
		local costItemId = costItem.itemId
		local costItemNum = costItem.itemNum

		local para =
		{
			refId = wndId,
			para = otherPara,
			func = callFunc,
			consume = {costItemNum, costItemId},
		}

		gModelGeneral:OpenUIOrdinTips(para,isTop)
	else
		callFunc()
	end

end

function ModelCallHero:SendIntegralCallHeroReq(refId,type, consumeRefId, wndName,isTop)
