	FireEvent(EventNames.ON_REQ_SUC)
	self:OnCallHeroReq(refId,callTimes, consumeRefId)
end

function ModelCallHero:SetCallReqProtect(isProtect)
	if isProtect then
		self._callHeroTime = 0
	else
		self._callHeroTime = Time.time
	end
end

function ModelCallHero:IsCallProtected()
	if not self._callHeroTime then
		return false
	end

	local timePast = Time.time - self._callHeroTime
	if timePast > 1 then
		return false
	end

	return true
end

---魔轮召唤请求
function ModelCallHero:SendMagicWheelReq(type,wheelType,wndName,func)
	if not self._wheelInfoMap then
		self._wheelInfoMap= {}
	end
	local serverData = self._wheelInfoMap[type]
	if not serverData then
		return
	end
	local todayCnt = serverData.extractCountToday
	local limitCnt = nil
	local callNum = 1
	local expend = nil
	local scoreStr = nil
	if type == ModelCallHero.LUCKY then
		limitCnt = self:GetMagicWheelConfigRefByKey("MagicWheelMaxNum")
		if wheelType == 1 then
			expend = self:GetMagicWheelConfigRefByKey("MagicWheelExpend")
		else
			callNum = self:GetMagicWheelConfigRefByKey("MagicWheelMoreNum")
			local vipLv = self:GetMagicWheelConfigRefByKey("MagicWheelDisMoreCondition")
			local currVipLv = gModelPlayer:GetVipLevel()
			if currVipLv >= vipLv then
				expend = self:GetMagicWheelConfigRefByKey("MagicWheelDisMoreExpend")
			else
				expend = self:GetMagicWheelConfigRefByKey("MagicWheelMoreExpend")
			end
		end
		scoreStr = self:GetMagicWheelConfigRefByKey("MagicWheelLuckNum")
	else
		limitCnt = self:GetMagicWheelConfigRefByKey("MagicWheelHighMaxNum")
		if wheelType == 1 then
			expend = self:GetMagicWheelConfigRefByKey("MagicWheelHighExpend")
		else
			callNum = self:GetMagicWheelConfigRefByKey("MagicWheelHighMoreNum")
			expend = self:GetMagicWheelConfigRefByKey("MagicWheelHighMoreExpend")
		end

		scoreStr = self:GetMagicWheelConfigRefByKey("MagicWheelHighLuckNum")
	end

	if todayCnt + callNum> limitCnt then
		GF.ShowMessage(ccClientText(11626))
		return
	end

	local cost = LxDataHelper.ParseItem_3(expend)
	local scoreReward = LxDataHelper.ParseItem_3(scoreStr)
	if not gModelGeneral:CheckItemEnough(cost.itemId,cost.itemNum) then
		gModelGeneral:OpenGetWayWnd({itemId = cost.itemId,srcWnd = wndName})
		return
	end

	local wndPara = nil
	local costStr = string.format("%s%s",cost.itemNum,gModelGeneral:GetCommonItemName(cost))
	local rewardStr  =string.format("%s%s",scoreReward.itemNum * callNum,gModelGeneral:GetCommonItemName(scoreReward))
	if type == ModelCallHero.LUCKY then
		wndPara =
		{
			refId = 101003,
			para = {costStr,rewardStr,callNum},
			func = function()
				if func then func() end
				self:OnMagicWheelReq(type,wheelType)
			end
		}
	else
		wndPara =
		{
			refId = 101004,
			para = {costStr,rewardStr,callNum},
			func = function()
				if func then func() end
				self:OnMagicWheelReq(type,wheelType)
			end
		}
	end


	gModelGeneral:OpenUIOrdinTips(wndPara)

	return true
end

function ModelCallHero:GetWheelCallNum(type,wheelType)
	local callNum = 1
	if type == ModelCallHero.LUCKY then
