function ModelCallHero:SendHeartCall(refId,type,wndName,isTop)
	if self:IsCallProtected() then
		return false
	end

	if not refId then
		GF.ShowMessage(ccClientText(11631))
		return
	end
	local refData = self:GetCallRefByRefId(refId)

	local times = nil
	local costItem = nil
	local payItem = nil

	if type == 1 then
		times = 1
		local oneExpend = LUtil.ConvertCommonItemStrToList(refData.oneExpend,"|")
		costItem = oneExpend[1]
		payItem = oneExpend[2]
	elseif type == 2 then
		times = 10
		local tenExpend = LUtil.ConvertCommonItemStrToList(refData.tenExpend,"|")
		costItem = tenExpend[1]
		payItem = tenExpend[2]
	end

	local payEnough = false
	local useItem = costItem
	local costEnough = gModelGeneral:CheckItemEnough(costItem.itemId,costItem.itemNum)
	if not costEnough and payItem then
		payEnough = gModelGeneral:CheckItemEnough(payItem.itemId,payItem.itemNum)
		useItem = payItem
	end

	if not (costEnough or payEnough) then
		local layer = LGameUI.UI_SORTLAYER_UIWND
		if isTop then
			layer = LGameUI.UI_SORTLAYER_UITOP
		end
		local getItem = costItem
		if payItem then
			getItem = payItem
		end
		gModelGeneral:OpenGetWayWnd({itemId=getItem.itemId,srcWnd = wndName},layer)
		return
	end

	if not costEnough and payEnough then
		local serverData = self._heartData[refId]
		if not serverData then
			return false
		end

		--添加钻石每日抽取上限
		local heartCallNumMax = GameTable.SummonConfigRef["heartCallNumMax"]
		if not string.isempty(heartCallNumMax) then
			if serverData.callNum + times > heartCallNumMax then
				GF.ShowMessage(ccClientText(11648))
				return false
			end
		end

		-- 【Y英雄召唤】删除日本地区的付费钻石召唤功能
		-- local heartDiamondTime = GameTable.SummonConfigRef["heartDiamondTime"]
		-- if not string.isempty(heartDiamondTime) then
		-- 	if serverData.diamondNum + times > heartDiamondTime then
		-- 		GF.ShowMessage(ccClientText(11648))
		-- 		return false
		-- 	end
		-- end
		--
	end

	local wndId = costEnough and 50501 or 50502
	local func = function()
		FireEvent(EventNames.ON_REQ_SUC)
		self:OnCallHeroReq(refId,times, useItem.itemId)
	end
	local fixName = gModelItem:GetNameByRefId(useItem.itemId)
	local payName = ccLngText(refData.typeName)
	local reward =LxDataHelper.ParseItem_3(refData.fixedReward)
	local rewardStr = string.format("%s%s",reward.itemNum,gModelGeneral:GetCommonItemName(reward))
	local para =
	{
		refId = wndId,
		func = func,
		para = {useItem.itemNum,fixName,rewardStr,times,payName}
	}

	gModelGeneral:OpenUIOrdinTips(para,isTop)
end

function ModelCallHero:GetRefIdHeroList(callRefId)
	local initCallRefIdHeroList = self._initCallRefIdHeroList
	if not initCallRefIdHeroList then
		initCallRefIdHeroList = {}
		self._initCallRefIdHeroList = initCallRefIdHeroList
	end
	local callRefIdHeroList = initCallRefIdHeroList[callRefId]
	if not callRefIdHeroList then
		callRefIdHeroList = {}
		local ref = self:GetCallRefByRefId(callRefId)
		if ref then
			local initStarIdList = gModelHero:GetInitStarIdList() or {}

			local showHero = string.split(ref.showHero,",")
			local startStar = tonumber(showHero[1]) or 3
			local endStar = tonumber(showHero[2]) or 5
			for star = startStar,endStar do
				local starHeroList = initStarIdList[star] or {}
				for i,heroRefId in ipairs(starHeroList) do
					if not self:CheckIsShieldHero(callRefId, heroRefId) then
						table.insert(callRefIdHeroList,heroRefId)
					end
				end
			end
		end
		initCallRefIdHeroList[callRefId] = callRefIdHeroList
	end
	return callRefIdHeroList
end

function ModelCallHero:GetRandomShowHero(callRefId)
	local callRefIdHeroList
	if callRefId == ModelCallHero.CALL_TYPE_PREPARE then
		callRefIdHeroList = self:GetPrepareMirrorCallHeroList()
	else
		callRefIdHeroList = self:GetRefIdHeroList(callRefId)
	end

	local len = #callRefIdHeroList
	if len < 1 then return end
	local randomNum = math.random(1,len)
	return callRefIdHeroList[randomNum]
end

function ModelCallHero:GetRaceHeroList(callRefId)
	local initRaceCallRefIdHeroList = self._initRaceCallRefIdHeroList
	if not initRaceCallRefIdHeroList then
		initRaceCallRefIdHeroList = {}
		self._initRaceCallRefIdHeroList = initRaceCallRefIdHeroList
	end

	local raceCallRefIdHeroList = initRaceCallRefIdHeroList[callRefId]
	if not raceCallRefIdHeroList then
		raceCallRefIdHeroList = {}
		local ref = self:GetCallRefByRefId(callRefId)
		if ref then
			local initRaceHeroList = gModelHero:GetInitRaceHeroList() or {}
			local showHero = string.split(ref.showHero,",")
			local startStar = tonumber(showHero[1]) or 3
			local endStar = tonumber(showHero[2]) or 5

			local race = ref.race
			local raceList = string.split(race,"|")
			local raceIdList = {}
			for i,v in ipairs(raceList) do
				table.insert(raceIdList,tonumber(v))
			end
			local initStar
			for i,v in ipairs(raceIdList) do
				local tList = initRaceHeroList[v] or {}
				for idx,val in ipairs(tList) do
					initStar = val.initStar
					if initStar >= startStar and initStar <= endStar then
						local heroRefId = val.heroRefId
						if not self:CheckIsShieldHero(callRefId, heroRefId) then
							table.insert(raceCallRefIdHeroList,heroRefId)
						end
					end
				end
			end
			initRaceCallRefIdHeroList[callRefId] = raceCallRefIdHeroList
		end
	end
	return raceCallRefIdHeroList
end

function ModelCallHero:GetRandomRaceShowHero(callRefId)
	local raceShowHeroList = self:GetRaceHeroList(callRefId)
	local len = #raceShowHeroList
	if len < 1 then return end
	local randomNum = math.random(1,len)
	return raceShowHeroList[randomNum]
end

