function ModelCallHero:GetIntegralCallHeroShowList(useHeroHeadList)
	local refIdHeroList = self:GetRefIdHeroList(ModelCallHero.CALL_TYPE_INTEGRAL)
	local noSelHeroList = {}
	for i,v in ipairs(refIdHeroList) do
		if not useHeroHeadList[v] then
			table.insert(noSelHeroList,v)
		end
	end
	local func = function()
		math.randomseed(tostring(os.time()))
		local randomNum = math.random(1,#noSelHeroList)
		local tHeroRefId = noSelHeroList[randomNum]
		return tHeroRefId
	end
	local tHero
	local selHeroRefIdList = {}
	for i,v in ipairs(noSelHeroList) do
		tHero = func()
		if tHero then
			table.insert(selHeroRefIdList,tHero)
		end
	end
	return selHeroRefIdList
end

function ModelCallHero:GetIntegralCallHeroList()
	local initIntegralCallHeroList = self._initIntegralCallHeroList
	if not initIntegralCallHeroList then
		initIntegralCallHeroList = {}
		self._initIntegralCallHeroList = initIntegralCallHeroList

		local ttHeroUseList = {}
		local reward,itemId
		for k,v in pairs(GameTable.SummonJackpotRef) do
			if v.jackpotId == ModelCallHero.CALL_TYPE_INTEGRAL then
				reward = LxDataHelper.ParseItem_3(v.reward)
				itemId = reward.itemId

				if ttHeroUseList[itemId] then
				else
					ttHeroUseList[itemId] = itemId
				end

				table.insert(initIntegralCallHeroList,{
					sort = v.sort,
					refId = k,
					itemType = reward.itemType,
					itemId = itemId,
					itemNum = reward.itemNum,
				})
			end
		end
		table.sort(initIntegralCallHeroList,function(a,b)
			return a.sort < b.sort
		end)
	end
	return initIntegralCallHeroList
end

function ModelCallHero:GetIntegralCallHeroShowNewList(useHeroHeadList,randomNum)
	useHeroHeadList = useHeroHeadList or {}
	randomNum = randomNum or 5
	local list = self:GetIntegralCallHeroList()
	local canUseHeroHeadList = {}
	local itemId
	local useStr
	for i,v in ipairs(list) do
		itemId = v.itemId
		if not useHeroHeadList[itemId] then
			table.insert(canUseHeroHeadList,{
				heroRefId = itemId,
			})
		else
			if useStr then
				useStr = useStr .. "," .. itemId
			else
				useStr = itemId
			end
		end
	end

	local randomFunc = function()
		local len = #canUseHeroHeadList
		if len < 1 then return end
		math.randomseed(os.time())
		local tRandomNum = math.random(1,len)
		return tRandomNum
	end


	local showStr
	local showList = {}
	local tIndex,tInfo
	for i = 1,randomNum do
		tIndex = randomFunc()
		if tIndex then
			tInfo = table.remove(canUseHeroHeadList,tIndex)
			if tInfo then
				table.insert(showList,tInfo.heroRefId)
				if showStr then
					showStr = showStr .. "," .. tInfo.heroRefId
				else
					showStr = tInfo.heroRefId
				end
			end
		end
	end
	return showList
end

