function ModelCallHero:CheckIsSpecialCallInDayAndHaveEnoughItem()
	local isOpen = self:CheckSpecialCallInCallValueDay()
	if not isOpen then return false end

	local callRefId = ModelCallHero.CALL_TYPE_SPECIAL
	local ref = self:GetCallRefByRefId(callRefId)
	if not ref then return false end

	local tenExpend = LUtil.ConvertCommonItemStrToList(ref.tenExpend,"|")
	local first = tenExpend[1]
	if not first then return false end

	local itemId = first.itemId
	local itemNum = first.itemNum
	local haveNum = gModelItem:GetNumByRefId(itemId)
	return haveNum >= itemNum
end


function ModelCallHero:SetPrepareMirrorCallData(selectId, getState)
	if selectId and selectId > 0 then
		self._prepareHeroId = selectId
		self:SetLocalPrepareMirrorCallData(nil, selectId)
	end

	if getState then
		-- 0 未领取，1 已领取
		self._canGetPrepareHero = getState == 0
	end
end

