function ModelCallHero:SetLocalPrepareMirrorCallData(haveNum, selectHeroId, addUseCallNum, callHeroList)
	local data = string.split(LPlayerPrefs.prepareMirrorCall, "=")
	local curHaveNum = haveNum or data[1] or ""
	local curHeroId  = selectHeroId or data[2] or ""
	local usedCallNum = tonumber(data[3]) or 0
	if addUseCallNum then
		usedCallNum = usedCallNum + addUseCallNum
	end

	local curCallHeroList = data[4] or ""
	if callHeroList then
		local callHeroStr
		for k,v in ipairs(callHeroList) do
			local heroId = v
			if not callHeroStr then
				callHeroStr = heroId
			else
				callHeroStr = callHeroStr..'|'..heroId
			end
		end
		curCallHeroList = callHeroStr or ""
	end

    local curFirstLoginTime = data[5] or gLGameLogin:GetTimeStamp()
	local sdkUserId = data[6] or gLGameLogin:GetAuthAccount() or ""

	local str = curHaveNum.."="..curHeroId.."="..usedCallNum.."="..curCallHeroList.."="..curFirstLoginTime.."="..sdkUserId
	LPlayerPrefs.SetPrepareMirrorCall(str)
end

