function ModelCallHero:GetPrepareMirrorCallHeroList()
	if not self._initPrepareCallHeroList then
		local ref = self:GetCallRefByRefId(ModelCallHero.CALL_TYPE_PREPARE)
		local jackpotId = ref.jackpotId

		local initPrepareCallHeroList = {}

		local reward,itemId
		local allProbabilityShow = 0
		for k,v in pairs(GameTable.SummonJackpotRef) do
			if v.jackpotId == jackpotId then
				reward = LxDataHelper.ParseItem_3(v.reward)
				itemId = reward.itemId
				local probabilityShow = v.probabilityShow * 100000
				local firstProbability = allProbabilityShow
				allProbabilityShow = allProbabilityShow + probabilityShow
				local endProbability  = allProbabilityShow
				table.insert(initPrepareCallHeroList,{
					sort = v.sort,
					refId = k,
					itemId = itemId,
					probabilityShow = probabilityShow,
					smallJackpot = v.smallJackpot,
					itemQuality = v.ItemQuality,
					firstProbability = firstProbability,
					endProbability = endProbability,
				})
			end
		end
		table.sort(initPrepareCallHeroList,function(a,b)
			return a.sort < b.sort
		end)

		self._initPrepareCallHeroList= {
			list = initPrepareCallHeroList,
			allProbability = allProbabilityShow,
		}
	end
	return self._initPrepareCallHeroList.list, self._initPrepareCallHeroList.allProbability
end

function ModelCallHero:GetPrepareMirrorCallHeroListBySmallJackPot(smallJackPot)
	if not self._initPrepareCallHeroSmallJackPotList then
		self._initPrepareCallHeroSmallJackPotList = {}
	end

	if not self._initPrepareCallHeroSmallJackPotList[smallJackPot] then
		local list = self:GetPrepareMirrorCallHeroList()
		local targetList = {}
		local allProbabilityShow = 0
		for k,v in ipairs(list) do
			if v.smallJackpot == smallJackPot then
				local probabilityShow = v.probabilityShow
				local firstProbability = allProbabilityShow
				allProbabilityShow = allProbabilityShow + probabilityShow
				local endProbability  = allProbabilityShow
				table.insert(targetList, {
					refId 			= v.refId,
					itemId 			= v.itemId,
					itemQuality 	= v.itemQuality,
					firstProbability = firstProbability,
					endProbability 	= endProbability,
				})
			end
		end

		self._initPrepareCallHeroSmallJackPotList[smallJackPot] = {
			list = targetList,
			allProbability = allProbabilityShow,
		}
	end

	local potList = self._initPrepareCallHeroSmallJackPotList[smallJackPot]
	local list = potList.list
	local allProbability = potList.allProbability
	return list, allProbability
end

function ModelCallHero:GetPrepareMirrorCallHeroListByCommonJackPot()
	if not self._initPrepareCallHeroSmallJackPotCommonList then
		self._initPrepareCallHeroSmallJackPotCommonList = {}

		local callRef = gModelCallHero:GetCallRefByRefId(ModelCallHero.CALL_TYPE_PREPARE)
		local tenCertainJackpot 		= callRef.tenCertainJackpot
		local accumulateJackpot 	= callRef.accumulateJackpot
		local list = self:GetPrepareMirrorCallHeroList()
		local targetList = {}
		local allProbabilityShow = 0
		for k,v in ipairs(list) do
			local smallJackpot = v.smallJackpot
			if smallJackpot ~= tenCertainJackpot and smallJackpot ~= accumulateJackpot then
				local probabilityShow = v.probabilityShow
				local firstProbability = allProbabilityShow
				allProbabilityShow = allProbabilityShow + probabilityShow
				local endProbability  = allProbabilityShow
				table.insert(targetList, {
					refId 			= v.refId,
					itemId 			= v.itemId,
					itemQuality 	= v.itemQuality,
					firstProbability = firstProbability,
					endProbability 	= endProbability,
				})
			end
		end

		self._initPrepareCallHeroSmallJackPotCommonList = {
			list = targetList,
			allProbability = allProbabilityShow,
		}
	end

	local potList = self._initPrepareCallHeroSmallJackPotCommonList
	local list = potList.list
	local allProbability = potList.allProbability
	return list, allProbability
end

function ModelCallHero:CheckHasGetPrepareMirrorCallSdk(sdkId)
	local localData = LPlayerPrefs.lockPrepareMirrorCallSdkList
	local list = string.split(localData, '=')
	for k,v in ipairs(list) do
		if v == sdkId then
			return true
		end
	end

	return false
end

function ModelCallHero:SetLockPrepareMirrorCallSdk(sdkId)
	if self:CheckHasGetPrepareMirrorCallSdk(sdkId) then
		return
	end

	local localData = LPlayerPrefs.lockPrepareMirrorCallSdkList
	local str
	if string.isempty(localData) then
		str = sdkId
	else
		str = localData.."="..sdkId
	end

	LPlayerPrefs.SetLockPrepareMirrorCallSdkList(str)
end


function ModelCallHero:AutoLockPrepareMirrorCallHero()
	if not gLGameLogin:IsOpenPreDrawCard() then
		return
	end

	local heroId = self:GetPrepareHeroId()
	if heroId then
		return
	end

	if self._canGetPrepareHero == false then
		return
	end

	local selectHeroId = self:GetLocalPrepareMirrorCallHero()
	if not selectHeroId or selectHeroId <= 0 then
		return
	end

	--local sdkUserId = gLGameLogin:GetAuthAccount()
	--local localSdkId = self:GetLocalPrepareMirrorSdkId()
	--if sdkUserId ~= localSdkId then
	--	return
	--end

	local serverTimeStamp = gLGameLogin:GetTimeStamp()
	local openTime = gLGameLogin:GetChannelOpenTime()
	if openTime and serverTimeStamp then
		local countDownTimeValue = openTime - serverTimeStamp
		if countDownTimeValue > 0 then
			return
		end
	end

	LPlayerPrefs.SetPrepareMirrorCall("")
	--自动锁定
	gLGameLogin:PreselectHeroRequestURL(false, selectHeroId)
end

function ModelCallHero:AutoClearLocalPrepareMirrorCallData(sdkUserId)
	if string.isempty(LPlayerPrefs.prepareMirrorCall) then
		return
	end

	local localSdkId = self:GetLocalPrepareMirrorSdkId()
	if sdkUserId ~= localSdkId then
		LPlayerPrefs.SetPrepareMirrorCall("")
		self:ClearPrepareMirrorCallData()
	end
end

